"""Точка входа приложения: инициализация (CoreBootstrap) и CLI/GUI."""from __future__ import annotationsimport sysfrom pathlib import Pathfrom src.core import AppConfigStorefrom src.core.app_path import project_rootfrom src.core.bootstrap import CoreBootstrapfrom src.core.logger import SYSTEM_LOGGER, get_system_loggerfrom src.modules.llm_models_registry.bootstrap import module_llm_model_registry_bootfrom src.modules.llm_providers.bootstrap import module_llm_providers_bootfrom src.modules.yandex_ocr.bootstrap import module_yandex_ocr_boot# Сначала boot ядра, затем регистрация модулей, затем boot модулейpaths = CoreBootstrap.core_boot(None)config = AppConfigStore.get()response_logger = get_system_logger() if config.core.debug else None# Эталонный реестр: в exe — из распакованных assets рядом с exe; при runtime — из репозитория assets/data_registry_filename = "llm_models_registry.json"_source_registry = (    paths.root / "assets" / "data" / _registry_filename    if getattr(sys, "frozen", False)    else project_root() / "assets" / "data" / _registry_filename)CoreBootstrap.add_module_boot(    lambda p: module_llm_model_registry_boot(        _source_registry,        p.data_user_dir / _registry_filename,    ))CoreBootstrap.add_module_boot(    lambda p: module_llm_providers_boot(        config=AppConfigStore.get().llm_providers,        response_logger=response_logger,        cache_path=None,    ))CoreBootstrap.add_module_boot(    lambda p: module_yandex_ocr_boot(        AppConfigStore.get().yandex_ocr,        response_logger=response_logger,        cache_path=p.cache_dir / "yandex_ocr",    ))CoreBootstrap.modules_boot(paths)app_root: Path = paths.rootdef main(project_name: str | None = None) -> None:    """Точка входа CLI: проверка проекта и валидация конфига по имени."""    if not project_name:        SYSTEM_LOGGER.warning("Укажите проект: uv run python main.py --cli --project <имя>")        if getattr(sys, "frozen", False):            input("Press Enter to exit...")        return    from src.modules.project import ProjectManager, validate_project_config    project_root = ProjectManager(app_root).get_project_root_by_name(project_name)    if project_root is None:        SYSTEM_LOGGER.warning(            "Проект не найден: %s. Создайте папку projects/%s и положите docs/ с документами.",            project_name,            project_name,        )        if getattr(sys, "frozen", False):            input("Press Enter to exit...")        return    validation = validate_project_config(project_root, check_tokens=True)    if not validation.is_valid:        for msg in validation.errors:            SYSTEM_LOGGER.error("Валидация конфига: %s", msg)        raise ValueError("Конфигурация проекта невалидна. Исправьте ошибки и повторите запуск.")    SYSTEM_LOGGER.info("Проект: %s (конфиг валиден). Пайплайн из CLI не запускается.", project_root)    if getattr(sys, "frozen", False):        input("Press Enter to exit...")